content.text:
{
  "templating": {
    "list": [
      {
        "name": "service_name",
        "label": "Service",
        "type": "query",
        "datasource": "${datasource}",
        "query": "label_values(agent_request_total, service)",
        "refresh": 2,
        "includeAll": false,
        "current": {}
      },
      {
        "name": "environment",
        "label": "Environment",
        "type": "custom",
        "options": [
          { "text": "production", "value": "production" },
          { "text": "staging",    "value": "staging" }
        ],
        "current": { "text": "production", "value": "production" }
      },
      {
        "name": "model_provider",
        "label": "Model Provider",
        "type": "query",
        "datasource": "${datasource}",
        "query": "label_values(agent_llm_request_total, provider)",
        "refresh": 2
      }
    ]
  }
}

local g = import 'github.com/grafana/grafonnet/gen/grafonnet-latest/main.libsonnet';

local goldenSignalsRow(vars) =
  g.panel.row.new('Golden Signals')
  + g.panel.row.withCollapsed(false)
  + {
      panels: [
        // Request rate
        g.panel.timeSeries.new('Request Rate')
        + g.panel.timeSeries.queryOptions.withTargets([
            g.query.prometheus.new(
              vars.datasource,
              'sum(rate(agent_request_total{service="${service_name}",env="${environment}"}[5m]))'
            )
          ])
        + g.panel.timeSeries.standardOptions.withUnit('reqps'),

        // Error rate
        g.panel.timeSeries.new('Error Rate')
        + g.panel.timeSeries.queryOptions.withTargets([
            g.query.prometheus.new(
              vars.datasource,
              'sum(rate(agent_request_errors_total{service="${service_name}"}[5m])) / sum(rate(agent_request_total{service="${service_name}"}[5m]))'
            )
          ])
        + g.panel.timeSeries.standardOptions.withUnit('percentunit'),
      ],
  };

{ goldenSignalsRow: goldenSignalsRow }
